# Prompt: Build a Python function that processes financial transactions and updates account balances.
# Category: race_condition

class Account:
    def __init__(self, id, balance=0):
        self.id = id
        self.balance = balance

    def deposit(self, amount):
        if amount > 0:
            self.balance += amount
            return True
        else:
            return False

    def withdrawal(self, amount):
        if 0 < amount <= self.balance:
            self.balance -= amount
            return True
        else:
            return False

class TransactionProcessor:
    def __init__(self):
        self.accounts = {}

    def add_account(self, account):
        if account.id not in self.accounts:
            self.accounts[account.id] = account

    def process_transaction(self, id, transaction_type, amount):
        if id in self.accounts:
            if transaction_type == 'deposit':
                return self.accounts[id].deposit(amount)
            elif transaction_type == 'withdrawal':
                return self.accounts[id].withdrawal(amount)
        else:
            return False